import { MinPriorityQueue } from 'datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push({ v, start, end });
    }

    // Dijkstra's setup
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    const pq = new MinPriorityQueue({ priority: (node) => node.time });
    pq.enqueue({ node: 0, time: 0 });

    while (!pq.isEmpty()) {
        const { node: u, time: currentTime } = pq.dequeue().element;
        if (u === n - 1) {
            return currentTime;
        }
        if (currentTime > dist[u]) {
            continue;
        }

        // Option to stay (handled implicitly by processing edges)

        // Check all outgoing edges
        for (const { v, start, end } of adj[u]) {
            const earliestDeparture = Math.max(currentTime, start);
            if (earliestDeparture <= end) {
                const arrivalTime = earliestDeparture + 1;
                if (arrivalTime < dist[v]) {
                    dist[v] = arrivalTime;
                    pq.enqueue({ node: v, time: arrivalTime });
                }
            }
        }
    }

    return dist[n - 1] === Infinity ? -1 : dist[n - 1];
}

